DROP POLICY IF EXISTS pipeline_restricted_access ON public.deal_activities;
CREATE POLICY deal_activities_select ON public.deal_activities FOR SELECT TO authenticated USING (EXISTS (SELECT 1 FROM deals d WHERE d.id = deal_activities.deal_id AND user_can_access_pipeline(d.pipeline_id)));
CREATE POLICY deal_activities_insert ON public.deal_activities FOR INSERT TO authenticated WITH CHECK (EXISTS (SELECT 1 FROM deals d WHERE d.id = deal_activities.deal_id AND user_can_access_pipeline(d.pipeline_id)));
CREATE POLICY deal_activities_update ON public.deal_activities FOR UPDATE TO authenticated USING (EXISTS (SELECT 1 FROM deals d WHERE d.id = deal_activities.deal_id AND user_can_access_pipeline(d.pipeline_id)) AND (app_role() IN ('admin','management') OR created_by_user_id = auth.uid())) WITH CHECK (EXISTS (SELECT 1 FROM deals d WHERE d.id = deal_activities.deal_id AND user_can_access_pipeline(d.pipeline_id)) AND (app_role() IN ('admin','management') OR created_by_user_id = auth.uid()));
CREATE POLICY deal_activities_delete ON public.deal_activities FOR DELETE TO authenticated USING (EXISTS (SELECT 1 FROM deals d WHERE d.id = deal_activities.deal_id AND user_can_access_pipeline(d.pipeline_id)) AND (app_role() IN ('admin','management') OR created_by_user_id = auth.uid()));
